import { useEffect, useState } from 'react';
import api from '../api/client';

export default function TicketList({
  refreshKey = 0,
}) {
  const [tickets, setTickets] =
    useState([]);

  const [
    ticketIdSearch,
    setTicketIdSearch,
  ] = useState('');

  const [
    departmentFilter,
    setDepartmentFilter,
  ] = useState('');

  const [
    moduleFilter,
    setModuleFilter,
  ] = useState('');

  const [
    submoduleFilter,
    setSubmoduleFilter,
  ] = useState('');

  const [
  bugTypeSearch,
  setBugTypeSearch,
] = useState('');

  const [
    createdFromDate,
    setCreatedFromDate,
  ] = useState('');

  const [
    createdToDate,
    setCreatedToDate,
  ] = useState('');

  const [
    closedFromDate,
    setClosedFromDate,
  ] = useState('');

  const [
    closedToDate,
    setClosedToDate,
  ] = useState('');

  const [departments, setDepartments] =
    useState([]);

  const [modules, setModules] =
    useState([]);

  const [submodules, setSubmodules] =
    useState([]);

  const [page, setPage] =
    useState(1);

  const [count, setCount] =
    useState(0);

  const [nextPage, setNextPage] =
    useState(null);

  const [
    previousPage,
    setPreviousPage,
  ] = useState(null);

  // LOAD DROPDOWNS
  const loadDropdowns =
    async () => {
      try {
        const [
          deptRes,
          moduleRes,
          submoduleRes,
        ] = await Promise.all([
          api.get(
            '/masters/departments/'
          ),
          api.get(
            '/masters/modules/'
          ),
          api.get(
            '/masters/submodules/'
          ),
        ]);

        setDepartments(
          deptRes.data.results ||
            deptRes.data ||
            []
        );

        setModules(
          moduleRes.data.results ||
            moduleRes.data ||
            []
        );

        setSubmodules(
          submoduleRes.data.results ||
            submoduleRes.data ||
            []
        );
      } catch (err) {
        console.error(err);
      }
    };

  // FILTER MODULES
  const filteredModules =
    !departmentFilter
      ? modules
      : modules.filter(
          (module) =>
            Number(
              module.department ||
                module.department_id
            ) ===
            Number(
              departmentFilter
            )
        );

  // FILTER SUBMODULES
  const filteredSubmodules =
    !moduleFilter
      ? submodules
      : submodules.filter(
          (submodule) =>
            Number(
              submodule.module
            ) ===
            Number(
              moduleFilter
            )
        );

  // LOAD TICKETS
  const loadTickets =
    async (pageNo = page) => {
      try {
        const params = {
          page: pageNo,
        };

        if (ticketIdSearch) {
          params.ticket_id =
            ticketIdSearch;
        }

        if (
          departmentFilter
        ) {
          params.department =
            departmentFilter;
        }

        if (moduleFilter) {
          params.module =
            moduleFilter;
        }

        if (
          submoduleFilter
        ) {
          params.submodule =
            submoduleFilter;
        }

        if (bugTypeSearch) {
 q
}

        // CREATED DATE
        if (
          createdFromDate &&
          createdToDate
        ) {
          params.created_from =
            createdFromDate;
          params.created_to =
            createdToDate;
        } else if (
          createdFromDate
        ) {
          params.created_date =
            createdFromDate;
        }

        // CLOSED DATE
        if (
          closedFromDate &&
          closedToDate
        ) {
          params.closed_from =
            closedFromDate;
          params.closed_to =
            closedToDate;
        } else if (
          closedFromDate
        ) {
          params.closed_date =
            closedFromDate;
        }

        const res =
          await api.get(
            '/tickets/',
            { params }
          );

        const data =
          res.data;

        setTickets(
          data.results || []
        );

        setCount(
          data.count || 0
        );

        setNextPage(
          data.next
        );

        setPreviousPage(
          data.previous
        );
      } catch (err) {
        console.error(
          'Ticket load failed:',
          err
        );
      }
    };

  useEffect(() => {
    loadDropdowns();
  }, []);

  useEffect(() => {
    loadTickets(page);
  }, [
    refreshKey,
    page,
    ticketIdSearch,
    departmentFilter,
    moduleFilter,
    submoduleFilter,
    createdFromDate,
    createdToDate,
    closedFromDate,
    closedToDate,
  ]);

  // RESET
  const handleResetFilters =
    () => {
      setTicketIdSearch('');
      setDepartmentFilter('');
      setModuleFilter('');
      setSubmoduleFilter('');
      setCreatedFromDate('');
      setCreatedToDate('');
      setClosedFromDate('');
      setClosedToDate('');
      setPage(1);
    };

  const totalPages =
    Math.ceil(count / 8);

  return (
    <div>
      {/* FILTERS */}
      <div className="row mb-3 g-2">

        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Ticket ID"
            value={ticketIdSearch}
            onChange={(e) =>
              setTicketIdSearch(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={departmentFilter}
            onChange={(e) => {
              setDepartmentFilter(
                e.target.value
              );
              setModuleFilter('');
              setSubmoduleFilter('');
            }}
          >
            <option value="">
              All Departments
            </option>

            {departments.map(
              (dept) => (
                <option
                  key={dept.id}
                  value={dept.id}
                >
                  {
                    dept.department_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={createdFromDate}
            onChange={(e) =>
              setCreatedFromDate(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={createdToDate}
            onChange={(e) =>
              setCreatedToDate(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={closedFromDate}
            onChange={(e) =>
              setClosedFromDate(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <input
            type="date"
            className="form-control"
            value={closedToDate}
            onChange={(e) =>
              setClosedToDate(
                e.target.value
              )
            }
          />
        </div>

      </div>

      <div className="mb-3">
        <button
          className="btn btn-secondary"
          onClick={
            handleResetFilters
          }
        >
          Reset
        </button>
      </div>

      {/* TABLE */}
      <div className="table-responsive">
        <table className="table table-bordered table-striped">
          <thead>
            <tr>
              <th>Ticket ID</th>
              <th>Department</th>
              <th>Subject</th>
              <th>Status</th>
              <th>Created Date</th>
              <th>Closed Date</th>
            </tr>
          </thead>

          <tbody>
            {tickets.length > 0 ? (
              tickets.map(
                (ticket) => (
                  <tr
                    key={
                      ticket.id
                    }
                  >
                    <td>
                      {
                        ticket.ticket_id
                      }
                    </td>
                    <td>
                      {
                        ticket.department_name
                      }
                    </td>
                    <td>
                      {
                        ticket.subject
                      }
                    </td>
                    <td>
                      {
                        ticket.status
                      }
                    </td>

                    <td>
                      {ticket.created_at
                        ? new Date(
                            ticket.created_at
                          ).toLocaleDateString()
                        : '-'}
                    </td>

                    <td>
                      {ticket.closed_at
                        ? new Date(
                            ticket.closed_at
                          ).toLocaleDateString()
                        : '-'}
                    </td>
                  </tr>
                )
              )
            ) : (
              <tr>
                <td
                  colSpan="6"
                  className="text-center"
                >
                  No tickets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* PAGINATION */}
      <div className="d-flex justify-content-between mt-3">
        <button
          className="btn btn-outline-secondary"
          disabled={!previousPage}
          onClick={() =>
            setPage(
              (prev) =>
                prev - 1
            )
          }
        >
          Previous
        </button>

        <span>
          Page {page} of{' '}
          {totalPages || 1}
        </span>

        <button
          className="btn btn-outline-secondary"
          disabled={!nextPage}
          onClick={() =>
            setPage(
              (prev) =>
                prev + 1
            )
          }
        >
          Next
        </button>
      </div>
    </div>
  );
}
